     1→"use client";
     2→
     3→import { useState } from "react";
     4→import useSWR, { mutate } from "swr";
     5→import {
     6→  subscriptions as subsApi,
     7→  channels as channelsApi,
     8→} from "@/lib/api/client";
     9→import { Plus, Pencil, Trash2 } from "lucide-react";
    10→import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
    11→import { ConfirmDialog } from "@/components/ui/confirm-dialog";
    12→import { SubscriptionForm } from "@/components/subscriptions/subscription-form";
    13→import type { Subscription } from "@/lib/api/types";
    14→
    15→const SUB_TYPE_COLORS: Record<string, { bg: string; text: string }> = {
    16→  source: { bg: "#1a1a1a", text: "#ffffff" },
    17→  project: { bg: "#2563eb", text: "#ffffff" },
    18→};
    19→
    20→function SubTypeBadge({ type }: { type: string }) {
    21→  const colors = SUB_TYPE_COLORS[type] ?? { bg: "#6b7280", text: "#ffffff" };
    22→  return (
    23→    <span
    24→      className="inline-flex items-center rounded-full px-2.5 py-0.5"
    25→      style={{
    26→        backgroundColor: colors.bg,
    27→        color: colors.text,
    28→        fontFamily: "var(--font-dm-sans)",
    29→        fontSize: "12px",
    30→        fontWeight: 500,
    31→        lineHeight: "16px",
    32→      }}
    33→    >
    34→      {type}
    35→    </span>
    36→  );
    37→}
    38→
    39→export default function SubscriptionsPage() {
    40→  const { data, isLoading } = useSWR("subscriptions", () => subsApi.list());
    41→  const { data: channelsData } = useSWR("channels-for-sub-list", () =>
    42→    channelsApi.list()
    43→  );
    44→
    45→  const [createOpen, setCreateOpen] = useState(false);
    46→  const [editingSub, setEditingSub] = useState<Subscription | null>(null);
    47→  const [deletingId, setDeletingId] = useState<string | null>(null);
    48→
    49→  const getChannelName = (id: string) =>
    50→    channelsData?.data.find((c) => c.id === id)?.name ?? id;
    51→
    52→  const subscriptions = data?.data ?? [];
    53→
    54→  return (
    55→    <div className="space-y-6">
    56→      {/* Header */}
    57→      <div className="flex items-center justify-between">
    58→        <h1
    59→          style={{
    60→            fontFamily: "var(--font-fraunces)",
    61→            fontSize: "24px",
    62→            fontWeight: 700,
    63→            color: "#111113",
    64→          }}
    65→        >
    66→          Subscriptions
    67→        </h1>
    68→        <button
    69→          onClick={() => setCreateOpen(true)}
    70→          className="inline-flex items-center gap-1.5 rounded-md px-3.5 py-2 transition-colors hover:opacity-90"
    71→          style={{
    72→            backgroundColor: "#e8601a",
    73→            color: "#ffffff",
    74→            fontFamily: "var(--font-dm-sans)",
    75→            fontSize: "13px",
    76→            fontWeight: 500,
    77→          }}
    78→        >
    79→          <Plus className="h-4 w-4" />
    80→          New Subscription
    81→        </button>
    82→      </div>
    83→
    84→      {/* Table card */}
    85→      <div
    86→        className="overflow-hidden rounded-lg bg-white"
    87→        style={{ border: "1px solid #e8e8e5" }}
    88→      >
    89→        {isLoading ? (
    90→          <div
    91→            className="py-16 text-center"
    92→            style={{
    93→              fontFamily: "var(--font-dm-sans)",
    94→              fontSize: "13px",
    95→              color: "#6b7280",
    96→            }}
    97→          >
    98→            Loading...
    99→          </div>
   100→        ) : subscriptions.length === 0 ? (
   101→          <div className="py-16 text-center">
   102→            <p
   103→              style={{
   104→                fontFamily: "var(--font-fraunces)",
   105→                fontStyle: "italic",
   106→                fontSize: "15px",
   107→                color: "#9ca3af",
   108→              }}
   109→            >
   110→              No subscriptions configured yet
   111→            </p>
   112→          </div>
   113→        ) : (
   114→          <table className="w-full">
   115→            <thead>
   116→              <tr style={{ backgroundColor: "#fafaf9" }}>
   117→                {["Type", "Target", "Channel", "Version Filter", "Actions"].map(
   118→                  (heading) => (
   119→                    <th
   120→                      key={heading}
   121→                      className="px-5 py-3 text-left"
   122→                      style={{
   123→                        fontFamily: "var(--font-dm-sans)",
   124→                        fontSize: "11px",
   125→                        fontWeight: 500,
   126→                        textTransform: "uppercase",
   127→                        letterSpacing: "0.08em",
   128→                        color: "#9ca3af",
   129→                        borderBottom: "1px solid #e8e8e5",
   130→                      }}
   131→                    >
   132→                      {heading}
   133→                    </th>
   134→                  )
   135→                )}
   136→              </tr>
   137→            </thead>
   138→            <tbody>
   139→              {subscriptions.map((sub) => (
   140→                <tr
   141→                  key={sub.id}
   142→                  className="transition-colors hover:bg-[#fafaf9]"
   143→                  style={{ borderBottom: "1px solid #e8e8e5" }}
   144→                >
   145→                  {/* Type */}
   146→                  <td className="px-5 py-3.5">
   147→                    <SubTypeBadge type={sub.type} />
   148→                  </td>
   149→
   150→                  {/* Target */}
   151→                  <td
   152→                    className="px-5 py-3.5"
   153→                    style={{
   154→                      fontFamily: "var(--font-dm-sans)",
   155→                      fontSize: "14px",
   156→                      fontWeight: 500,
   157→                      color: "#111113",
   158→                    }}
   159→                  >
   160→                    {sub.type === "source" ? sub.source_id : sub.project_id}
   161→                  </td>
   162→
   163→                  {/* Channel */}
   164→                  <td
   165→                    className="px-5 py-3.5"
   166→                    style={{
   167→                      fontFamily: "var(--font-dm-sans)",
   168→                      fontSize: "14px",
   169→                      color: "#111113",
   170→                    }}
   171→                  >
   172→                    {getChannelName(sub.channel_id)}
   173→                  </td>
   174→
   175→                  {/* Version Filter */}
   176→                  <td
   177→                    className="px-5 py-3.5"
   178→                    style={{
   179→                      fontFamily: sub.version_filter
   180→                        ? "'JetBrains Mono', monospace"
   181→                        : "var(--font-dm-sans)",
   182→                      fontSize: "13px",
   183→                      color: sub.version_filter ? "#111113" : "#9ca3af",
   184→                    }}
   185→                  >
   186→                    {sub.version_filter || "\u2014"}
   187→                  </td>
   188→
   189→                  {/* Actions */}
   190→                  <td className="px-5 py-3.5">
   191→                    <div className="flex items-center gap-2">
   192→                      <button
   193→                        onClick={() => setEditingSub(sub)}
   194→                        className="rounded p-1 text-[#9ca3af] transition-colors hover:bg-[#f3f3f1] hover:text-[#111113]"
   195→                      >
   196→                        <Pencil className="h-4 w-4" />
   197→                      </button>
   198→                      <button
   199→                        onClick={() => setDeletingId(sub.id)}
   200→                        className="rounded p-1 text-[#9ca3af] transition-colors hover:bg-red-50 hover:text-red-600"
   201→                      >
   202→                        <Trash2 className="h-4 w-4" />
   203→                      </button>
   204→                    </div>
   205→                  </td>
   206→                </tr>
   207→              ))}
   208→            </tbody>
   209→          </table>
   210→        )}
   211→      </div>
   212→
   213→      {/* Create dialog */}
   214→      <Dialog open={createOpen} onOpenChange={setCreateOpen}>
   215→        <DialogContent className="sm:max-w-lg">
   216→          <DialogHeader>
   217→            <DialogTitle>Create Subscription</DialogTitle>
   218→          </DialogHeader>
   219→          <SubscriptionForm
   220→            title="Create Subscription"
   221→            onSubmit={async (input) => {
   222→              await subsApi.create(input);
   223→            }}
   224→            onSuccess={() => {
   225→              setCreateOpen(false);
   226→              mutate("subscriptions");
   227→            }}
   228→            onCancel={() => setCreateOpen(false)}
   229→          />
   230→        </DialogContent>
   231→      </Dialog>
   232→
   233→      {/* Edit dialog */}
   234→      <Dialog
   235→        open={!!editingSub}
   236→        onOpenChange={(open) => {
   237→          if (!open) setEditingSub(null);
   238→        }}
   239→      >
   240→        <DialogContent className="sm:max-w-lg">
   241→          <DialogHeader>
   242→            <DialogTitle>Edit Subscription</DialogTitle>
   243→          </DialogHeader>
   244→          {editingSub && (
   245→            <SubscriptionForm
   246→              key={editingSub.id}
   247→              title="Edit Subscription"
   248→              initial={editingSub}
   249→              onSubmit={async (input) => {
   250→                await subsApi.update(editingSub.id, input);
   251→              }}
   252→              onSuccess={() => {
   253→                setEditingSub(null);
   254→                mutate("subscriptions");
   255→              }}
   256→              onCancel={() => setEditingSub(null)}
   257→            />
   258→          )}
   259→        </DialogContent>
   260→      </Dialog>
   261→
   262→      {/* Delete dialog */}
   263→      <ConfirmDialog
   264→        open={!!deletingId}
   265→        onOpenChange={(open) => {
   266→          if (!open) setDeletingId(null);
   267→        }}
   268→        title="Delete Subscription"
   269→        description="This will permanently delete this subscription. This cannot be undone."
   270→        onConfirm={async () => {
   271→          if (deletingId) {
   272→            await subsApi.delete(deletingId);
   273→            mutate("subscriptions");
   274→          }
   275→        }}
   276→      />
   277→    </div>
   278→  );
   279→}
   280→

