     1→"use client";
     2→
     3→import { useState } from "react";
     4→import { useRouter } from "next/navigation";
     5→import useSWR from "swr";
     6→import { projects as projectsApi, channels as channelsApi, sources as sourcesApi } from "@/lib/api/client";
     7→import { Button } from "@/components/ui/button";
     8→import { Input } from "@/components/ui/input";
     9→import { Label } from "@/components/ui/label";
    10→import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
    11→import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
    12→import type { Subscription, SubscriptionInput } from "@/lib/api/types";
    13→
    14→interface SubscriptionFormProps {
    15→  initial?: Subscription;
    16→  onSubmit: (input: SubscriptionInput) => Promise<void>;
    17→  title: string;
    18→  onSuccess?: () => void;
    19→  onCancel?: () => void;
    20→}
    21→
    22→export function SubscriptionForm({ initial, onSubmit, title, onSuccess, onCancel }: SubscriptionFormProps) {
    23→  const router = useRouter();
    24→  const [saving, setSaving] = useState(false);
    25→  const [error, setError] = useState("");
    26→  const [type, setType] = useState<"source" | "project">(initial?.type ?? "project");
    27→  const [channelId, setChannelId] = useState(initial?.channel_id ?? "");
    28→  const [projectId, setProjectId] = useState(initial?.project_id ?? "");
    29→  const [sourceId, setSourceId] = useState(initial?.source_id ?? "");
    30→  const [versionFilter, setVersionFilter] = useState(initial?.version_filter ?? "");
    31→
    32→  const { data: projectsData } = useSWR("projects-for-sub", () => projectsApi.list());
    33→  const { data: channelsData } = useSWR("channels-for-sub", () => channelsApi.list());
    34→  const { data: sourcesData } = useSWR(
    35→    type === "source" && projectId ? `sources-for-sub-${projectId}` : null,
    36→    () => sourcesApi.listByProject(projectId)
    37→  );
    38→
    39→  const handleSubmit = async (e: React.FormEvent) => {
    40→    e.preventDefault();
    41→    setError("");
    42→    setSaving(true);
    43→    try {
    44→      await onSubmit({
    45→        channel_id: channelId,
    46→        type,
    47→        source_id: type === "source" ? sourceId : undefined,
    48→        project_id: type === "project" ? projectId : undefined,
    49→        version_filter: versionFilter || undefined,
    50→      });
    51→      if (onSuccess) {
    52→        onSuccess();
    53→      } else {
    54→        router.push("/subscriptions");
    55→      }
    56→    } catch (err: unknown) {
    57→      setError(err instanceof Error ? err.message : "Failed to save");
    58→    } finally {
    59→      setSaving(false);
    60→    }
    61→  };
    62→
    63→  const formContent = (
    64→    <form onSubmit={handleSubmit} className="space-y-4">
    65→      {error && <div className="rounded-md bg-red-50 p-3 text-sm text-red-700">{error}</div>}
    66→      <div className="space-y-2">
    67→        <Label>Subscription Type</Label>
    68→        <Select value={type} onValueChange={(v) => setType(v as "source" | "project")}>
    69→          <SelectTrigger><SelectValue /></SelectTrigger>
    70→          <SelectContent>
    71→            <SelectItem value="project">Project</SelectItem>
    72→            <SelectItem value="source">Source</SelectItem>
    73→          </SelectContent>
    74→        </Select>
    75→      </div>
    76→      {type === "project" && (
    77→        <div className="space-y-2">
    78→          <Label>Project</Label>
    79→          <Select value={projectId} onValueChange={setProjectId} required>
    80→            <SelectTrigger><SelectValue placeholder="Select project" /></SelectTrigger>
    81→            <SelectContent>
    82→              {projectsData?.data.map((p) => (
    83→                <SelectItem key={p.id} value={p.id}>{p.name}</SelectItem>
    84→              ))}
    85→            </SelectContent>
    86→          </Select>
    87→        </div>
    88→      )}
    89→      {type === "source" && (
    90→        <>
    91→          <div className="space-y-2">
    92→            <Label>Project (to list sources)</Label>
    93→            <Select value={projectId} onValueChange={(v) => { setProjectId(v); setSourceId(""); }}>
    94→              <SelectTrigger><SelectValue placeholder="Select project" /></SelectTrigger>
    95→              <SelectContent>
    96→                {projectsData?.data.map((p) => (
    97→                  <SelectItem key={p.id} value={p.id}>{p.name}</SelectItem>
    98→                ))}
    99→              </SelectContent>
   100→            </Select>
   101→          </div>
   102→          <div className="space-y-2">
   103→            <Label>Source</Label>
   104→            <Select value={sourceId} onValueChange={setSourceId} required>
   105→              <SelectTrigger><SelectValue placeholder="Select source" /></SelectTrigger>
   106→              <SelectContent>
   107→                {sourcesData?.data.map((s) => (
   108→                  <SelectItem key={s.id} value={s.id}>{s.provider}: {s.repository}</SelectItem>
   109→                ))}
   110→              </SelectContent>
   111→            </Select>
   112→          </div>
   113→        </>
   114→      )}
   115→      <div className="space-y-2">
   116→        <Label>Notification Channel</Label>
   117→        <Select value={channelId} onValueChange={setChannelId} required>
   118→          <SelectTrigger><SelectValue placeholder="Select channel" /></SelectTrigger>
   119→          <SelectContent>
   120→            {channelsData?.data.map((ch) => (
   121→              <SelectItem key={ch.id} value={ch.id}>{ch.name} ({ch.type})</SelectItem>
   122→            ))}
   123→          </SelectContent>
   124→        </Select>
   125→      </div>
   126→      <div className="space-y-2">
   127→        <Label htmlFor="version_filter">Version Filter (regex, optional)</Label>
   128→        <Input id="version_filter" value={versionFilter} onChange={(e) => setVersionFilter(e.target.value)} placeholder='e.g. ^v\d+\.\d+\.\d+$' />
   129→      </div>
   130→      <div className="flex justify-end gap-2">
   131→        <Button type="button" variant="outline" onClick={() => onCancel ? onCancel() : router.back()}>Cancel</Button>
   132→        <Button type="submit" disabled={saving}>{saving ? "Saving..." : "Save"}</Button>
   133→      </div>
   134→    </form>
   135→  );
   136→
   137→  if (onSuccess) {
   138→    return formContent;
   139→  }
   140→
   141→  return (
   142→    <Card className="mx-auto max-w-2xl">
   143→      <CardHeader><CardTitle>{title}</CardTitle></CardHeader>
   144→      <CardContent>
   145→        {formContent}
   146→      </CardContent>
   147→    </Card>
   148→  );
   149→}
   150→

