"use client";

import { useState } from "react";
import useSWR, { mutate } from "swr";
import {
  subscriptions as subsApi,
  channels as channelsApi,
} from "@/lib/api/client";
import { Plus, Pencil, Trash2 } from "lucide-react";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { ConfirmDialog } from "@/components/ui/confirm-dialog";
import { SubscriptionForm } from "@/components/subscriptions/subscription-form";
import type { Subscription } from "@/lib/api/types";

const SUB_TYPE_COLORS: Record<string, { bg: string; text: string }> = {
  source: { bg: "#1a1a1a", text: "#ffffff" },
  project: { bg: "#2563eb", text: "#ffffff" },
};

function SubTypeBadge({ type }: { type: string }) {
  const colors = SUB_TYPE_COLORS[type] ?? { bg: "#6b7280", text: "#ffffff" };
  return (
    <span
      className="inline-flex items-center rounded-full px-2.5 py-0.5"
      style={{
        backgroundColor: colors.bg,
        color: colors.text,
        fontFamily: "var(--font-dm-sans)",
        fontSize: "12px",
        fontWeight: 500,
        lineHeight: "16px",
      }}
    >
      {type}
    </span>
  );
}

export default function SubscriptionsPage() {
  const { data, isLoading } = useSWR("subscriptions", () => subsApi.list());
  const { data: channelsData } = useSWR("channels-for-sub-list", () =>
    channelsApi.list()
  );

  const [createOpen, setCreateOpen] = useState(false);
  const [editingSub, setEditingSub] = useState<Subscription | null>(null);
  const [deletingId, setDeletingId] = useState<string | null>(null);

  const getChannelName = (id: string) =>
    channelsData?.data.find((c) => c.id === id)?.name ?? id;

  const subscriptions = data?.data ?? [];

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <h1
          style={{
            fontFamily: "var(--font-fraunces)",
            fontSize: "24px",
            fontWeight: 700,
            color: "#111113",
          }}
        >
          Subscriptions
        </h1>
        <button
          onClick={() => setCreateOpen(true)}
          className="inline-flex items-center gap-1.5 rounded-md px-3.5 py-2 transition-colors hover:opacity-90"
          style={{
            backgroundColor: "#e8601a",
            color: "#ffffff",
            fontFamily: "var(--font-dm-sans)",
            fontSize: "13px",
            fontWeight: 500,
          }}
        >
          <Plus className="h-4 w-4" />
          New Subscription
        </button>
      </div>

      {/* Table card */}
      <div
        className="overflow-hidden rounded-lg bg-white"
        style={{ border: "1px solid #e8e8e5" }}
      >
        {isLoading ? (
          <div
            className="py-16 text-center"
            style={{
              fontFamily: "var(--font-dm-sans)",
              fontSize: "13px",
              color: "#6b7280",
            }}
          >
            Loading...
          </div>
        ) : subscriptions.length === 0 ? (
          <div className="py-16 text-center">
            <p
              style={{
                fontFamily: "var(--font-fraunces)",
                fontStyle: "italic",
                fontSize: "15px",
                color: "#9ca3af",
              }}
            >
              No subscriptions configured yet
            </p>
          </div>
        ) : (
          <table className="w-full">
            <thead>
              <tr style={{ backgroundColor: "#fafaf9" }}>
                {["Type", "Target", "Channel", "Version Filter", "Actions"].map(
                  (heading) => (
                    <th
                      key={heading}
                      className="px-5 py-3 text-left"
                      style={{
                        fontFamily: "var(--font-dm-sans)",
                        fontSize: "11px",
                        fontWeight: 500,
                        textTransform: "uppercase",
                        letterSpacing: "0.08em",
                        color: "#9ca3af",
                        borderBottom: "1px solid #e8e8e5",
                      }}
                    >
                      {heading}
                    </th>
                  )
                )}
              </tr>
            </thead>
            <tbody>
              {subscriptions.map((sub) => (
                <tr
                  key={sub.id}
                  className="transition-colors hover:bg-[#fafaf9]"
                  style={{ borderBottom: "1px solid #e8e8e5" }}
                >
                  {/* Type */}
                  <td className="px-5 py-3.5">
                    <SubTypeBadge type={sub.type} />
                  </td>

                  {/* Target */}
                  <td
                    className="px-5 py-3.5"
                    style={{
                      fontFamily: "var(--font-dm-sans)",
                      fontSize: "14px",
                      fontWeight: 500,
                      color: "#111113",
                    }}
                  >
                    {sub.type === "source" ? sub.source_id : sub.project_id}
                  </td>

                  {/* Channel */}
                  <td
                    className="px-5 py-3.5"
                    style={{
                      fontFamily: "var(--font-dm-sans)",
                      fontSize: "14px",
                      color: "#111113",
                    }}
                  >
                    {getChannelName(sub.channel_id)}
                  </td>

                  {/* Version Filter */}
                  <td
                    className="px-5 py-3.5"
                    style={{
                      fontFamily: sub.version_filter
                        ? "'JetBrains Mono', monospace"
                        : "var(--font-dm-sans)",
                      fontSize: "13px",
                      color: sub.version_filter ? "#111113" : "#9ca3af",
                    }}
                  >
                    {sub.version_filter || "\u2014"}
                  </td>

                  {/* Actions */}
                  <td className="px-5 py-3.5">
                    <div className="flex items-center gap-2">
                      <button
                        onClick={() => setEditingSub(sub)}
                        className="rounded p-1 text-[#9ca3af] transition-colors hover:bg-[#f3f3f1] hover:text-[#111113]"
                      >
                        <Pencil className="h-4 w-4" />
                      </button>
                      <button
                        onClick={() => setDeletingId(sub.id)}
                        className="rounded p-1 text-[#9ca3af] transition-colors hover:bg-red-50 hover:text-red-600"
                      >
                        <Trash2 className="h-4 w-4" />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>

      {/* Create dialog */}
      <Dialog open={createOpen} onOpenChange={setCreateOpen}>
        <DialogContent className="sm:max-w-lg">
          <DialogHeader>
            <DialogTitle>Create Subscription</DialogTitle>
          </DialogHeader>
          <SubscriptionForm
            title="Create Subscription"
            onSubmit={async (input) => {
              await subsApi.create(input);
            }}
            onSuccess={() => {
              setCreateOpen(false);
              mutate("subscriptions");
            }}
            onCancel={() => setCreateOpen(false)}
          />
        </DialogContent>
      </Dialog>

      {/* Edit dialog */}
      <Dialog
        open={!!editingSub}
        onOpenChange={(open) => {
          if (!open) setEditingSub(null);
        }}
      >
        <DialogContent className="sm:max-w-lg">
          <DialogHeader>
            <DialogTitle>Edit Subscription</DialogTitle>
          </DialogHeader>
          {editingSub && (
            <SubscriptionForm
              key={editingSub.id}
              title="Edit Subscription"
              initial={editingSub}
              onSubmit={async (input) => {
                await subsApi.update(editingSub.id, input);
              }}
              onSuccess={() => {
                setEditingSub(null);
                mutate("subscriptions");
              }}
              onCancel={() => setEditingSub(null)}
            />
          )}
        </DialogContent>
      </Dialog>

      {/* Delete dialog */}
      <ConfirmDialog
        open={!!deletingId}
        onOpenChange={(open) => {
          if (!open) setDeletingId(null);
        }}
        title="Delete Subscription"
        description="This will permanently delete this subscription. This cannot be undone."
        onConfirm={async () => {
          if (deletingId) {
            await subsApi.delete(deletingId);
            mutate("subscriptions");
          }
        }}
      />
    </div>
  );
}

// web/lib/api/client.ts
import type {
  ApiResponse,
  Project,
  ProjectInput,
  Release,
  Source,
  SourceInput,
  Subscription,
  SubscriptionInput,
  NotificationChannel,
  ChannelInput,
  ContextSource,
  ContextSourceInput,
  SemanticRelease,
  AgentRun,
  HealthStatus,
  Stats,
  TrendData,
} from "./types";

const BASE = process.env.NEXT_PUBLIC_API_URL || "/api/v1";

async function request<T>(path: string, init?: RequestInit): Promise<T> {
  const res = await fetch(`${BASE}${path}`, {
    headers: { "Content-Type": "application/json", ...init?.headers },
    ...init,
  });
  if (!res.ok) {
    const body = await res.json().catch(() => null);
    throw new Error(body?.error?.message ?? `Request failed: ${res.status}`);
  }
  if (res.status === 204) return null as T;
  return res.json();
}

// --- Projects ---

export const projects = {
  list: (page = 1, perPage = 25) =>
    request<ApiResponse<Project[]>>(`/projects?page=${page}&per_page=${perPage}`),
  get: (id: string) =>
    request<ApiResponse<Project>>(`/projects/${id}`),
  create: (input: ProjectInput) =>
    request<ApiResponse<Project>>("/projects", {
      method: "POST",
      body: JSON.stringify(input),
    }),
  update: (id: string, input: ProjectInput) =>
    request<ApiResponse<Project>>(`/projects/${id}`, {
      method: "PUT",
      body: JSON.stringify(input),
    }),
  delete: (id: string) =>
    request<ApiResponse<null>>(`/projects/${id}`, { method: "DELETE" }),
};

// --- Sources (nested under projects) ---

export const sources = {
  listByProject: (projectId: string, page = 1) =>
    request<ApiResponse<Source[]>>(`/projects/${projectId}/sources?page=${page}`),
  create: (projectId: string, input: SourceInput) =>
    request<ApiResponse<Source>>(`/projects/${projectId}/sources`, {
      method: "POST",
      body: JSON.stringify(input),
    }),
  get: (id: string) =>
    request<ApiResponse<Source>>(`/sources/${id}`),
  update: (id: string, input: SourceInput) =>
    request<ApiResponse<Source>>(`/sources/${id}`, {
      method: "PUT",
      body: JSON.stringify(input),
    }),
  delete: (id: string) =>
    request<ApiResponse<null>>(`/sources/${id}`, { method: "DELETE" }),
  poll: (id: string) =>
    request<ApiResponse<{ new_releases: number }>>(`/sources/${id}/poll`, {
      method: "POST",
    }),
};

export const releases = {
  list: (page = 1, perPage = 25) =>
    request<ApiResponse<Release[]>>(`/releases?page=${page}&per_page=${perPage}`),
  listBySource: (sourceId: string, page = 1) =>
    request<ApiResponse<Release[]>>(`/sources/${sourceId}/releases?page=${page}`),
  listByProject: (projectId: string, page = 1, perPage = 25) =>
    request<ApiResponse<Release[]>>(`/projects/${projectId}/releases?page=${page}&per_page=${perPage}`),
  get: (id: string) =>
    request<ApiResponse<Release>>(`/releases/${id}`),
};

// --- Context Sources ---

export const contextSources = {
  list: (projectId: string, page = 1) =>
    request<ApiResponse<ContextSource[]>>(`/projects/${projectId}/context-sources?page=${page}`),
  create: (projectId: string, input: ContextSourceInput) =>
    request<ApiResponse<ContextSource>>(`/projects/${projectId}/context-sources`, {
      method: "POST",
      body: JSON.stringify(input),
    }),
  get: (id: string) =>
    request<ApiResponse<ContextSource>>(`/context-sources/${id}`),
  update: (id: string, input: ContextSourceInput) =>
    request<ApiResponse<ContextSource>>(`/context-sources/${id}`, {
      method: "PUT",
      body: JSON.stringify(input),
    }),
  delete: (id: string) =>
    request<ApiResponse<null>>(`/context-sources/${id}`, { method: "DELETE" }),
};

// --- Semantic Releases ---

export const semanticReleases = {
  listAll: (page = 1, perPage = 25) =>
    request<ApiResponse<SemanticRelease[]>>(`/semantic-releases?page=${page}&per_page=${perPage}`),
  list: (projectId: string, page = 1, perPage = 25) =>
    request<ApiResponse<SemanticRelease[]>>(`/projects/${projectId}/semantic-releases?page=${page}&per_page=${perPage}`),
  get: (id: string) =>
    request<ApiResponse<SemanticRelease>>(`/semantic-releases/${id}`),
  delete: (id: string) =>
    request<ApiResponse<null>>(`/semantic-releases/${id}`, { method: "DELETE" }),
};

// --- Agent ---

export const agent = {
  triggerRun: (projectId: string, version?: string) =>
    request<ApiResponse<AgentRun>>(`/projects/${projectId}/agent/run`, {
      method: "POST",
      body: JSON.stringify({ trigger: "test", version: version || undefined }),
    }),
  listRuns: (projectId: string, page = 1) =>
    request<ApiResponse<AgentRun[]>>(`/projects/${projectId}/agent/runs?page=${page}`),
  getRun: (id: string) =>
    request<ApiResponse<AgentRun>>(`/agent-runs/${id}`),
};

// --- Subscriptions ---

export const subscriptions = {
  list: () => request<ApiResponse<Subscription[]>>("/subscriptions"),
  get: (id: string) => request<ApiResponse<Subscription>>(`/subscriptions/${id}`),
  create: (input: SubscriptionInput) =>
    request<ApiResponse<Subscription>>("/subscriptions", {
      method: "POST",
      body: JSON.stringify(input),
    }),
  update: (id: string, input: SubscriptionInput) =>
    request<ApiResponse<Subscription>>(`/subscriptions/${id}`, {
      method: "PUT",
      body: JSON.stringify(input),
    }),
  delete: (id: string) =>
    request<ApiResponse<null>>(`/subscriptions/${id}`, { method: "DELETE" }),
};

// --- Notification Channels ---

export const channels = {
  list: () => request<ApiResponse<NotificationChannel[]>>("/channels"),
  get: (id: string) => request<ApiResponse<NotificationChannel>>(`/channels/${id}`),
  create: (input: ChannelInput) =>
    request<ApiResponse<NotificationChannel>>("/channels", {
      method: "POST",
      body: JSON.stringify(input),
    }),
  update: (id: string, input: ChannelInput) =>
    request<ApiResponse<NotificationChannel>>(`/channels/${id}`, {
      method: "PUT",
      body: JSON.stringify(input),
    }),
  delete: (id: string) =>
    request<ApiResponse<null>>(`/channels/${id}`, { method: "DELETE" }),
  test: (id: string) =>
    request<ApiResponse<{ status: string }>>(`/channels/${id}/test`, {
      method: "POST",
    }),
};

// --- System ---

export const system = {
  health: () => request<HealthStatus>("/health"),
  stats: () => request<ApiResponse<Stats>>("/stats"),
  trend: (granularity: "daily" | "weekly" | "monthly" = "daily", days = 7) =>
    request<ApiResponse<TrendData>>(`/stats/trend?granularity=${granularity}&days=${days}`),
};

